package requirements {
    requirement def Shape {
        doc /* The system shall fit within a maximum external cube envelope of 1 m x 1 m x 1 m. */
    }

    requirement def Material {
        doc /* The system structural shell shall be made of 2024 Aluminium. */
    }

    requirement def Construction {
        doc /* The system shall be a hollow, thin-walled construction and shall not be a solid cube. */
    }

    requirement def Weight {
        doc /* The system shall weigh no more than 1kg. */
    }
}

