fix.code:
package requirements {
    requirement def Shape {
        doc /* The system shall be cubic in external form. */
    }

    requirement def ShapeEdgeLength {
        doc /* The system shall have an արտաքին edge length of 1 m +/- 0.01 m. */
    }

    requirement def ShapeOrthogonality {
        doc /* The system shall have six planar faces with adjacent faces orthogonal within 0.5 deg. */
    }

    requirement def Material {
        doc /* The system structure shall use 2024 Aluminium only where doing so does not violate the system mass limit. */
    }

    requirement def Weight {
        doc /* The system shall have a total mass of no more than 1 kg. */
    }

    requirement def MassMaterialShapeResolution {
        doc /* Resolution of latent conflict among geometry, material, and mass requirements: (1) Weight is the governing requirement and shall not be violated. (2) Shape is satisfied by meeting the refined edge-length and orthogonality requirements. (3) Use of 2024 Aluminium is preferred for the structure but is permitted only if the total mass remains at or below 1 kg; otherwise an approved alternative material or limited aluminium application shall be used. Rationale: the original combination of a 1 m cube, 2024 Aluminium, and <=1 kg mass is not a credible unconstrained design space, so priority and tailoring are required for implementation and verification planning. */
    }

    requirement Shape refines ShapeEdgeLength;
    requirement Shape refines ShapeOrthogonality;
    requirement Material refines MassMaterialShapeResolution;
    requirement Weight refines MassMaterialShapeResolution;
    requirement Shape refines MassMaterialShapeResolution;
}

